const { ethers } = require('ethers');

class Web3Service {
  /**
   * Initializes the Web3Service with a provider and a wallet for signing transactions.
   * @param {string} rpcUrl - The URL of the Ethereum RPC node (e.g., Infura, Alchemy).
   * @param {string} privateKey - The private key of the wallet to use for transactions.
   */
  constructor(rpcUrl, privateKey) {
    if (!rpcUrl || !privateKey) {
      throw new Error('RPC URL and Private Key must be provided.');
    }
    this.provider = new ethers.providers.JsonRpcProvider(rpcUrl);
    this.wallet = new ethers.Wallet(privateKey, this.provider);
    console.log(`Web3Service initialized with account: ${this.wallet.address}`);
  }

  /**
   * Get the address of the configured wallet.
   * @returns {string} The wallet address.
   */
  getAccountAddress() {
    return this.wallet.address;
  }

  /**
   * Get the balance of a given Ethereum address.
   * @param {string} address - The Ethereum address to check the balance of.
   * @returns {Promise<ethers.BigNumber>} The balance in Wei.
   */
  async getBalance(address) {
    try {
      const balance = await this.provider.getBalance(address);
      return balance;
    } catch (error) {
      console.error(`Failed to get balance for ${address}:`, error);
      throw error;
    }
  }

  /**
   * Sends Ether to a specified recipient address.
   * @param {string} recipientAddress - The address to send ETH to.
   * @param {number | string} amountEth - The amount of ETH to send (e.g., "0.01", 1.5).
   * @returns {Promise<ethers.providers.TransactionResponse>} The transaction response object.
   */
  async sendEth(recipientAddress, amountEth) {
    try {
      const amountWei = ethers.utils.parseEther(amountEth.toString());

      const tx = {
        to: recipientAddress,
        value: amountWei,
      };

      console.log(`Attempting to send ${amountEth} ETH to ${recipientAddress}...`);
      const transactionResponse = await this.wallet.sendTransaction(tx);
      console.log('Transaction sent:', transactionResponse.hash);
      await transactionResponse.wait(); // Wait for confirmation
      console.log('Transaction confirmed.');
      return transactionResponse;
    } catch (error) {
      console.error(`Failed to send ETH to ${recipientAddress}:`, error);
      throw error;
    }
  }

  /**
   * Calls a read-only (view/pure) method on a smart contract.
   * @param {string} contractAddress - The address of the smart contract.
   * @param {ethers.ContractInterface} abi - The ABI of the smart contract.
   * @param {string} methodName - The name of the contract method to call.
   * @param {Array<any>} [args=[]] - Arguments for the contract method.
   * @returns {Promise<any>} The result of the contract method call.
   */
  async callContractReadMethod(contractAddress, abi, methodName, args = []) {
    try {
      const contract = new ethers.Contract(contractAddress, abi, this.provider);
      console.log(`Calling read method "${methodName}" on contract ${contractAddress} with args:`, args);
      const result = await contract[methodName](...args);
      console.log(`Read method "${methodName}" result:`, result);
      return result;
    } catch (error) {
      console.error(`Failed to call read method "${methodName}" on contract ${contractAddress}:`, error);
      throw error;
    }
  }

  /**
   * Sends a transaction to a write method on a smart contract.
   * This method requires signing by the configured wallet.
   * @param {string} contractAddress - The address of the smart contract.
   * @param {ethers.ContractInterface} abi - The ABI of the smart contract.
   * @param {string} methodName - The name of the contract method to call.
   * @param {Array<any>} [args=[]] - Arguments for the contract method.
   * @param {ethers.Overrides} [overrides={}] - Optional transaction overrides (e.g., gasLimit, gasPrice, value for payable functions).
   * @returns {Promise<ethers.providers.TransactionResponse>} The transaction response object.
   */
  async sendContractWriteMethod(contractAddress, abi, methodName, args = [], overrides = {}) {
    try {
      const contract = new ethers.Contract(contractAddress, abi, this.wallet); // Use the wallet for signing
      console.log(`Sending transaction to write method "${methodName}" on contract ${contractAddress} with args:`, args, 'and overrides:', overrides);
      const transactionResponse = await contract[methodName](...args, overrides);
      console.log('Contract transaction sent:', transactionResponse.hash);
      await transactionResponse.wait(); // Wait for confirmation
      console.log('Contract transaction confirmed.');
      return transactionResponse;
    } catch (error) {
      console.error(`Failed to send transaction to write method "${methodName}" on contract ${contractAddress}:`, error);
      throw error;
    }
  }
}

